     1→// Scripted response mapping - videos with baked-in audio
     2→const SCRIPTED_RESPONSES = {
     3→  // Judgmental responses
     4→  "ew that's gross": {
     5→    video: 'assets/videos/scripted/judgmental_gross.mp4',
     6→    emotion: 'judgmental',
     7→    keywords: ['gross', 'ew', 'disgusting', 'ugly']
     8→  },
     9→  "oh no honey what is that": {
    10→    video: 'assets/videos/scripted/judgmental_honey.mp4',
    11→    emotion: 'judgmental',
    12→    keywords: ['honey', 'what is that', 'oh no']
    13→  },
    14→  "that's... a choice": {
    15→    video: 'assets/videos/scripted/judgmental_choice.mp4',
    16→    emotion: 'judgmental',
    17→    keywords: ['choice', 'interesting choice', 'bold']
    18→  },
    19→  
    20→  // Confused responses
    21→  "why would you wear that": {
    22→    video: 'assets/videos/scripted/confused_why.mp4',
    23→    emotion: 'confused',
    24→    keywords: ['why', 'wear that', 'why would']
    25→  },
    26→  "wait what is happening here": {
    27→    video: 'assets/videos/scripted/confused_what.mp4',
    28→    emotion: 'confused',
    29→    keywords: ['what is happening', 'what', 'wait']
    30→  },
    31→  "i'm so confused right now": {
    32→    video: 'assets/videos/scripted/confused_lost.mp4',
    33→    emotion: 'confused',
    34→    keywords: ['confused', 'lost', 'don\'t understand']
    35→  },
    36→  
    37→  // Positive responses
    38→  "okay i love that": {
    39→    video: 'assets/videos/scripted/positive_love.mp4',
    40→    emotion: 'excited',
    41→    keywords: ['love', 'love that', 'love it']
    42→  },
    43→  "yes this is it": {
    44→    video: 'assets/videos/scripted/positive_yes.mp4',
    45→    emotion: 'excited',
    46→    keywords: ['yes', 'this is it', 'perfect']
    47→  },
    48→  "you look amazing": {
    49→    video: 'assets/videos/scripted/positive_amazing.mp4',
    50→    emotion: 'happy',
    51→    keywords: ['amazing', 'look amazing', 'stunning', 'gorgeous']
    52→  },
    53→  
    54→  // Neutral responses
    55→  "hmm let me see": {
    56→    video: 'assets/videos/scripted/neutral_see.mp4',
    57→    emotion: 'thinking',
    58→    keywords: ['hmm', 'let me see', 'thinking']
    59→  },
    60→  "okay here's the thing": {
    61→    video: 'assets/videos/scripted/neutral_thing.mp4',
    62→    emotion: 'thinking',
    63→    keywords: ['here\'s the thing', 'the thing is', 'okay so']
    64→  },
    65→  
    66→  // Supportive responses
    67→  "you know what it works": {
    68→    video: 'assets/videos/scripted/supportive_works.mp4',
    69→    emotion: 'happy',
    70→    keywords: ['it works', 'works', 'actually works']
    71→  },
    72→  "not bad at all": {
    73→    video: 'assets/videos/scripted/supportive_notbad.mp4',
    74→    emotion: 'happy',
    75→    keywords: ['not bad', 'pretty good', 'decent']
    76→  }
    77→};
    78→
    79→// Find best matching scripted response
    80→function findScriptedResponse(text) {
    81→  const lowerText = text.toLowerCase();
    82→  
    83→  // First, try exact match
    84→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
    85→    if (lowerText.includes(phrase)) {
    86→      return { phrase, ...data };
    87→    }
    88→  }
    89→  
    90→  // Then, try keyword matching
    91→  let bestMatch = null;
    92→  let bestScore = 0;
    93→  
    94→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
    95→    let score = 0;
    96→    for (const keyword of data.keywords) {
    97→      if (lowerText.includes(keyword)) {
    98→        score += keyword.length; // longer keyword matches = better
    99→      }
   100→    }
   101→    if (score > bestScore) {
   102→      bestScore = score;
   103→      bestMatch = { phrase, ...data };
   104→    }
   105→  }
   106→  
   107→  // Only return if we have a decent match
   108→  return bestScore >= 4 ? bestMatch : null;
   109→}
   110→
   111→// Get emotion from response for fallback video selection
   112→function detectEmotion(text) {
   113→  const lowerText = text.toLowerCase();
   114→  
   115→  // Check for emotion indicators
   116→  if (/ew|gross|ugly|terrible|awful|yuck|no no|honey/.test(lowerText)) {
   117→    return 'concerned'; // judgmental uses concerned video
   118→  }
   119→  if (/confused|what|why|huh|\?{2,}|don't understand/.test(lowerText)) {
   120→    return 'thinking';
   121→  }
   122→  if (/love|amazing|perfect|yes!|gorgeous|stunning|beautiful|great/.test(lowerText)) {
   123→    return 'excited';
   124→  }
   125→  if (/good|nice|works|not bad|decent|okay|fine/.test(lowerText)) {
   126→    return 'happy';
   127→  }
   128→  if (/hmm|let me|thinking|consider/.test(lowerText)) {
   129→    return 'thinking';
   130→  }
   131→  
   132→  return 'talking'; // default
   133→}
