     1→// Gemini API for outfit analysis
     2→class GeminiAnalyzer {
     3→  constructor(apiKey) {
     4→    this.apiKey = apiKey;
     5→    this.model = CONFIG.GEMINI_MODEL;
     6→    this.baseUrl = 'https://generativelanguage.googleapis.com/v1beta/models';
     7→  }
     8→
     9→  async analyzeOutfit(imageBase64, userPrompt = '') {
    10→    // Remove data URL prefix if present
    11→    const base64Data = imageBase64.replace(/^data:image\/\w+;base64,/, '');
    12→    
    13→    const prompt = userPrompt || "What do you think of my outfit?";
    14→    
    15→    const requestBody = {
    16→      contents: [{
    17→        parts: [
    18→          {
    19→            text: `${CONFIG.SYSTEM_PROMPT}\n\nUser says: "${prompt}"\n\nLook at what they're wearing and respond as Mira.`
    20→          },
    21→          {
    22→            inline_data: {
    23→              mime_type: 'image/jpeg',
    24→              data: base64Data
    25→            }
    26→          }
    27→        ]
    28→      }],
    29→      generationConfig: {
    30→        temperature: 0.8,
    31→        maxOutputTokens: 200,
    32→        topP: 0.9
    33→      }
    34→    };
    35→
    36→    try {
    37→      const response = await fetch(
    38→        `${this.baseUrl}/${this.model}:generateContent?key=${this.apiKey}`,
    39→        {
    40→          method: 'POST',
    41→          headers: {
    42→            'Content-Type': 'application/json'
    43→          },
    44→          body: JSON.stringify(requestBody)
    45→        }
    46→      );
    47→
    48→      if (!response.ok) {
    49→        const error = await response.json();
    50→        throw new Error(error.error?.message || 'API request failed');
    51→      }
    52→
    53→      const data = await response.json();
    54→      
    55→      // Extract text from response
    56→      const text = data.candidates?.[0]?.content?.parts?.[0]?.text;
    57→      if (!text) {
    58→        throw new Error('No response generated');
    59→      }
    60→      
    61→      return text.trim();
    62→    } catch (err) {
    63→      console.error('Gemini API error:', err);
    64→      throw err;
    65→    }
    66→  }
    67→}
    68→
    69→let gemini = null;
    70→
    71→function initGemini() {
    72→  if (CONFIG.GEMINI_API_KEY && CONFIG.GEMINI_API_KEY !== 'YOUR_GEMINI_API_KEY') {
    73→    gemini = new GeminiAnalyzer(CONFIG.GEMINI_API_KEY);
    74→    return true;
    75→  }
    76→  return false;
    77→}
