     1→// Webcam handling
     2→class WebcamManager {
     3→  constructor() {
     4→    this.video = document.getElementById('webcam');
     5→    this.canvas = document.getElementById('snapshot');
     6→    this.stream = null;
     7→    this.initialized = false;
     8→  }
     9→
    10→  async init() {
    11→    try {
    12→      this.stream = await navigator.mediaDevices.getUserMedia({
    13→        video: {
    14→          width: { ideal: 1280 },
    15→          height: { ideal: 720 },
    16→          facingMode: 'user'
    17→        },
    18→        audio: false
    19→      });
    20→      
    21→      this.video.srcObject = this.stream;
    22→      this.initialized = true;
    23→      console.log('Webcam initialized');
    24→      return true;
    25→    } catch (err) {
    26→      console.error('Webcam error:', err);
    27→      alert('Could not access webcam. Please allow camera permissions.');
    28→      return false;
    29→    }
    30→  }
    31→
    32→  captureFrame() {
    33→    if (!this.initialized) return null;
    34→    
    35→    const ctx = this.canvas.getContext('2d');
    36→    this.canvas.width = this.video.videoWidth;
    37→    this.canvas.height = this.video.videoHeight;
    38→    
    39→    // Draw current frame
    40→    ctx.drawImage(this.video, 0, 0);
    41→    
    42→    // Return as base64 JPEG
    43→    return this.canvas.toDataURL('image/jpeg', 0.8);
    44→  }
    45→
    46→  captureFrameAsBlob() {
    47→    return new Promise((resolve) => {
    48→      if (!this.initialized) {
    49→        resolve(null);
    50→        return;
    51→      }
    52→      
    53→      const ctx = this.canvas.getContext('2d');
    54→      this.canvas.width = this.video.videoWidth;
    55→      this.canvas.height = this.video.videoHeight;
    56→      ctx.drawImage(this.video, 0, 0);
    57→      
    58→      this.canvas.toBlob((blob) => {
    59→        resolve(blob);
    60→      }, 'image/jpeg', 0.8);
    61→    });
    62→  }
    63→
    64→  stop() {
    65→    if (this.stream) {
    66→      this.stream.getTracks().forEach(track => track.stop());
    67→      this.stream = null;
    68→      this.initialized = false;
    69→    }
    70→  }
    71→}
    72→
    73→const webcam = new WebcamManager();
    74→

